from pathlib import Path
import re, base64
p = Path('index.html')
s = p.read_text(encoding='utf-8')
style = base64.b64decode('').decode('utf-8')
html = base64.b64decode('').decode('utf-8')
if '.hero-main{' not in s:
    s = s.replace('\n  </style>', style + '\n  </style>', 1)
s = re.sub(r'(<section id="home" class="page hero">\s*<div class="hero-inner">\s*).*?(\s*<div class="social-icons">)', r'\1' + html + r'\2', s, count=1, flags=re.S)
p.write_text(s, encoding='utf-8')
